python3 -c "
import json, sys, os, re
d = json.load(sys.stdin)
ti = d.get('tool_input', {})
p = ti.get('file_path', '')
if not p or not p.endswith('.cs'):
    sys.exit(0)
skip = ['Test', '.test.', '.Tests', 'Migrations']
if any(s in p for s in skip):
    sys.exit(0)
content = ti.get('content', '') or ti.get('new_string', '')
if not content:
    sys.exit(0)
usings = re.findall(r'using\s+([\w.]+)\s*;', content)
if not usings:
    sys.exit(0)
def has_layer(ns, keywords):
    return any(k in ns.lower() for k in keywords)
bn = os.path.basename(p).lower()
violations = []
if 'controller' in bn:
    for ns in usings:
        if has_layer(ns, ['repository', 'repositories', 'entity', 'entities']):
            if not has_layer(ns, ['dto', 'service', 'interface']):
                violations.append(f'Controller uses {ns} (should go through Service layer)')
elif 'service' in bn:
    for ns in usings:
        if has_layer(ns, ['controller', 'controllers']):
            violations.append(f'Service uses {ns} (controllers depend on services, not vice versa)')
if violations:
    msg = '; '.join(violations[:2])
    print(json.dumps({'systemMessage': f'[BOUNDARY] {msg}. See coding-conventions.md Layer Boundaries.'}))
sys.exit(0)
"
